module RollbackTrigger =
  struct
    type nonrec t =
      {
      arn: Arn.t
        [@ocaml.doc
          "The Amazon Resource Name (ARN) of the rollback trigger. If a specified trigger is missing, the entire stack operation fails and is rolled back."];
      type_: Type.t
        [@ocaml.doc
          "The resource type of the rollback trigger. Specify either AWS::CloudWatch::Alarm or AWS::CloudWatch::CompositeAlarm resource types."]}
    let context_ = "RollbackTrigger"
    let make ~arn = fun ~type_ -> fun () -> { arn; type_ }
    let to_value x =
      structure_to_value
        [("Arn", (Some (Arn.to_value x.arn)));
        ("Type", (Some (Type.to_value x.type_)))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let type_ =
        Type.of_xml (Xml.child_exn ~context:context_ xml_arg0 "Type") in
      let arn = Arn.of_xml (Xml.child_exn ~context:context_ xml_arg0 "Arn") in
      make ~type_ ~arn ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let type_ = field_map_exn json__ "Type" Type.of_json in
      let arn = field_map_exn json__ "Arn" Arn.of_json in make ~type_ ~arn ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "A rollback trigger CloudFormation monitors during creation and updating of stacks. If any of the alarms you specify goes to ALARM state during the stack operation or within the specified monitoring period afterwards, CloudFormation rolls back the entire stack operation."]
